+        try {
+            ByteBuffer bb = encoder().encode(CharBuffer.wrap(s));
+            if (bb.hasArray() && bb.remaining() == bb.capacity()) {
+                return bb.array();
+            }
+            byte[] bytes = new byte[bb.remaining()];
+            bb.get(bytes);
+            return bytes;
+        } catch (CharacterCodingException x) {
+            throw new IllegalArgumentException(x);
